import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getMyRfqs } from "../../features/b2b/b2bSlice";
import B2bLayout from "./B2bLayout";
import {
  FileQuestion, Clock, CheckCircle2, XCircle, ArrowRight,
  Search, FileSpreadsheet, Plus, X, Package,
} from "lucide-react";

/* ─────────────────────────────────────────────────────────────
   Tokens
───────────────────────────────────────────────────────────── */
const statusCfg = {
  PENDING:  { label: "Pending",        badge: "bg-amber-50   text-amber-700   ring-1 ring-amber-200",   icon: Clock          },
  QUOTED:   { label: "Quoted",         badge: "bg-indigo-50  text-indigo-700  ring-1 ring-indigo-200",  icon: FileSpreadsheet },
  ACCEPTED: { label: "Accepted Quote", badge: "bg-emerald-50 text-emerald-700 ring-1 ring-emerald-200", icon: CheckCircle2   },
  REJECTED: { label: "Rejected",       badge: "bg-red-50     text-red-600     ring-1 ring-red-200",     icon: XCircle        },
};

const Badge = ({ status }) => {
  const cfg = statusCfg[status] || statusCfg.PENDING;
  const Icon = cfg.icon;
  return (
    <span className={`inline-flex items-center gap-1.5 text-[11px] font-semibold px-2.5 py-1 rounded-full ${cfg.badge}`}>
      <Icon size={11} />
      {cfg.label}
    </span>
  );
};

/* ─────────────────────────────────────────────────────────────
   Skeleton row
───────────────────────────────────────────────────────────── */
const SkeletonRow = () => (
  <div className="bg-white border border-slate-200/80 rounded-xl p-5 animate-pulse flex items-center gap-4">
    <div className="w-10 h-10 bg-slate-100 rounded-xl shrink-0" />
    <div className="flex-1 space-y-2">
      <div className="h-3.5 w-32 bg-slate-100 rounded" />
      <div className="h-3 w-64 bg-slate-100 rounded" />
    </div>
    <div className="w-20 h-3 bg-slate-100 rounded" />
  </div>
);

/* ─────────────────────────────────────────────────────────────
   Main
───────────────────────────────────────────────────────────── */
const B2bRfqList = () => {
  const dispatch = useDispatch();
  const { rfqs, isLoading } = useSelector((s) => s.b2b);
  const [statusFilter, setStatusFilter] = useState("");
  const [search,       setSearch      ] = useState("");

  useEffect(() => {
    const p = {};
    if (statusFilter) p.status = statusFilter;
    dispatch(getMyRfqs(p));
  }, [dispatch, statusFilter]);

  const filtered = (rfqs || []).filter((r) => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (
      r.rfqNumber?.toLowerCase().includes(q) ||
      r.notes?.toLowerCase().includes(q) ||
      r.items?.some(
        (i) =>
          i.product?.title?.toLowerCase().includes(q) ||
          i.genericName?.toLowerCase().includes(q)
      )
    );
  });

  return (
    <B2bLayout>

      {/* ── Header ── */}
      <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4 mb-7">
        <div>
          <h1 className="text-[22px] font-bold text-slate-900 tracking-tight">RFQ Submissions</h1>
          <p className="text-[13px] text-slate-500 mt-1">
            Request custom quotes and bulk pricing for your procurement needs.
          </p>
        </div>
        <Link
          to="/b2b/rfq/new"
          className="inline-flex items-center gap-2 h-10 px-4 bg-slate-900 hover:bg-blue-600 text-white text-[13px] font-semibold rounded-lg transition-colors shadow-sm self-start shrink-0"
        >
          <Plus size={15} /> New Request
        </Link>
      </div>

      {/* ── Toolbar ── */}
      <div className="bg-white border border-slate-200/80 rounded-xl shadow-sm mb-5 overflow-hidden">
        <div className="flex items-center gap-2.5 px-3 py-3">
          <div className="relative flex-1 min-w-0">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
            <input
              type="text"
              placeholder="Search by RFQ number, product, or notes…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-9 pr-8 h-9 bg-slate-50 border border-slate-200 rounded-lg text-[13px] placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition-all"
            />
            {search && (
              <button onClick={() => setSearch("")} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600">
                <X size={13} />
              </button>
            )}
          </div>
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="h-9 px-3 bg-slate-50 border border-slate-200 rounded-lg text-[13px] font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/20 cursor-pointer hover:bg-slate-100 transition-colors shrink-0"
          >
            <option value="">All Statuses</option>
            {Object.entries(statusCfg).map(([k, v]) => (
              <option key={k} value={k}>{v.label}</option>
            ))}
          </select>
        </div>
      </div>

      {/* ── Count ── */}
      {!isLoading && filtered.length > 0 && (
        <p className="text-[12px] text-slate-400 font-medium mb-4">
          {filtered.length} RFQ{filtered.length !== 1 ? "s" : ""}
        </p>
      )}

      {/* ── List ── */}
      {isLoading ? (
        <div className="flex flex-col gap-3">
          {[1, 2, 3].map((i) => <SkeletonRow key={i} />)}
        </div>
      ) : filtered.length > 0 ? (
        <div className="flex flex-col gap-3">
          {filtered.map((rfq) => {
            const cfg  = statusCfg[rfq.status] || statusCfg.PENDING;
            const Icon = cfg.icon;
            const date = rfq.createdAt
              ? new Date(rfq.createdAt).toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" })
              : "—";
            const itemNames = rfq.items
              ?.slice(0, 3)
              .map((i) => i.product?.title || i.genericName || "Custom item")
              .join(", ");

            return (
              <Link
                key={rfq.id}
                to={`/b2b/rfq/${rfq.id}`}
                className="group bg-white border border-slate-200/80 rounded-xl shadow-sm hover:shadow-md hover:-translate-y-px transition-all duration-150 flex flex-col sm:flex-row sm:items-center gap-4 p-5 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
              >
                {/* Icon */}
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${cfg.badge}`}>
                  <Icon size={17} />
                </div>

                {/* Main info */}
                <div className="flex-1 min-w-0">
                  <div className="flex flex-wrap items-center gap-2 mb-1">
                    <span className="text-[14px] font-semibold text-slate-900 group-hover:text-blue-600 transition-colors">
                      {rfq.rfqNumber || `RFQ-${rfq.id?.slice(0, 8).toUpperCase()}`}
                    </span>
                    <Badge status={rfq.status} />
                    <span className="text-[11px] text-slate-400">{date}</span>
                  </div>

                  {/* Items preview */}
                  <p className="text-[12px] text-slate-500 truncate">
                    <span className="font-medium text-slate-600">{rfq.items?.length || 0} items</span>
                    {itemNames && <span className="ml-1.5 text-slate-400">— {itemNames}{rfq.items?.length > 3 ? "…" : ""}</span>}
                  </p>

                  {rfq.notes && (
                    <p className="text-[11px] text-slate-400 italic mt-0.5 truncate">"{rfq.notes}"</p>
                  )}
                </div>

                {/* Quoted indicator */}
                <div className="flex items-center gap-3 shrink-0">
                  {rfq.status === "QUOTED" && (
                    <div className="hidden sm:flex flex-col items-end">
                      <span className="text-[10px] font-semibold text-indigo-500 uppercase tracking-wider">Quote Ready</span>
                      <span className="text-[11px] text-slate-500 font-medium">Review supplier offer</span>
                    </div>
                  )}
                  <ArrowRight
                    size={16}
                    className="text-slate-300 group-hover:text-blue-500 group-hover:translate-x-0.5 transition-all"
                  />
                </div>
              </Link>
            );
          })}
        </div>
      ) : (
        /* Empty state */
        <div className="flex flex-col items-center justify-center py-24 bg-white border border-slate-200/80 rounded-xl shadow-sm text-center px-6">
          <div className="w-14 h-14 bg-slate-100 rounded-2xl flex items-center justify-center mb-4">
            <FileQuestion size={28} className="text-slate-300" />
          </div>
          <p className="text-[14px] font-semibold text-slate-700">No RFQs found</p>
          <p className="text-[12px] text-slate-400 mt-1 max-w-xs">
            {search || statusFilter
              ? "No requests match your filters."
              : "Submit your first quote request to get started."}
          </p>
          <Link
            to="/b2b/rfq/new"
            className="mt-5 inline-flex items-center gap-2 h-9 px-4 bg-slate-900 hover:bg-blue-600 text-white text-[12px] font-semibold rounded-lg transition-colors"
          >
            <Package size={14} /> New RFQ Request
          </Link>
        </div>
      )}

    </B2bLayout>
  );
};

export default B2bRfqList;
