import React, { useEffect, useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { getB2bProfile } from "../../features/b2b/b2bSlice";
import { ShoppingCart, User, LogOut, CheckCircle2, Menu, X, ChevronDown } from "lucide-react";

const B2bHeader = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useDispatch();

  const customer = useSelector((state) => state.auth?.user);
  const { profile } = useSelector((state) => state.b2b);
  const [cartCount, setCartCount] = useState(0);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    if (customer && !profile) dispatch(getB2bProfile());
  }, [dispatch, customer, profile]);

  useEffect(() => {
    const update = () => {
      try {
        const raw = localStorage.getItem("b2b_cart");
        const parsed = raw ? JSON.parse(raw) : [];
        setCartCount(Array.isArray(parsed) ? parsed.length : 0);
      } catch { setCartCount(0); }
    };
    update();
    window.addEventListener("b2b_cart_update", update);
    return () => window.removeEventListener("b2b_cart_update", update);
  }, []);

  const handleLogout = () => {
    localStorage.clear();
    navigate("/login");
    window.location.reload();
  };

  const isActive = (path) =>
    path === "/b2b"
      ? location.pathname === "/b2b"
      : location.pathname.startsWith(path);

  const navLinks = [
    { label: "Catalog", path: "/b2b" },
    { label: "RFQ Submissions", path: "/b2b/rfq" },
    { label: "My Orders", path: "/b2b/orders" },
  ];

  return (
    <>
      {/* ── Main Bar ── */}
      <header className="sticky top-0 z-50 bg-[#0d1526] border-b border-white/[0.07] shadow-[0_2px_24px_rgba(0,0,0,0.35)]">
        {/* inner: exactly 80px tall */}
        <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-10 h-[80px] flex items-center justify-between gap-4">

          {/* ── Logo ── */}
          <Link to="/b2b" className="flex items-center gap-3 shrink-0 group">
            <div className="w-[42px] h-[42px] rounded-xl overflow-hidden border border-white/10 shadow-md group-hover:border-blue-500/40 transition-all">
              <img src="/logo3.png" alt="Pulse Addis" className="w-full h-full object-contain" />
            </div>
            <div className="leading-tight">
              <p className="font-black text-[15px] sm:text-[16px] tracking-tight text-white uppercase leading-none">
                Pulse <span className="text-blue-400">Addis</span>
              </p>
              <p className="text-[9px] text-slate-500 font-bold tracking-[0.18em] mt-[3px]">
                Wholesale Procurement
              </p>
            </div>
          </Link>

          {/* ── Desktop Nav ── */}
          <nav className="hidden md:flex items-center gap-1 flex-1 justify-center">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`relative px-4 py-2 rounded-xl text-[13px] font-bold transition-all duration-150 ${
                  isActive(link.path)
                    ? "text-blue-400 bg-blue-500/10"
                    : "text-slate-400 hover:text-white hover:bg-white/5"
                }`}
              >
                {link.label}
                {isActive(link.path) && (
                  <span className="absolute bottom-0 left-1/2 -translate-x-1/2 w-5 h-[2px] bg-blue-400 rounded-full" />
                )}
              </Link>
            ))}
          </nav>

          {/* ── Right Controls ── */}
          <div className="flex items-center gap-2 shrink-0">
            {/* Account info pill — desktop only */}
            {profile && (
              <div className="hidden lg:flex items-center gap-2 h-9 px-3 bg-white/5 border border-white/10 rounded-xl">
                {profile.isVerified ? (
                  <CheckCircle2 size={13} className="text-emerald-400 shrink-0" />
                ) : (
                  <span className="w-2 h-2 rounded-full bg-amber-400 animate-pulse shrink-0" />
                )}
                <div className="flex flex-col leading-none">
                  <span className="text-[11px] font-black text-white truncate max-w-[130px]">
                    {profile.institutionName}
                  </span>
                  <span className="text-[9px] text-slate-500 font-bold uppercase tracking-wider mt-0.5">
                    {profile.isVerified ? "Prepaid Account" : "Under Verification"}
                  </span>
                </div>
              </div>
            )}

            {/* Cart */}
            <Link
              to="/b2b/cart"
              aria-label="Cart"
              className="relative flex items-center justify-center w-10 h-10 bg-white/5 border border-white/10 rounded-xl text-slate-300 hover:text-white hover:bg-white/10 hover:border-white/20 transition-all"
            >
              <ShoppingCart size={17} />
              {cartCount > 0 && (
                <span className="absolute -top-1.5 -right-1.5 bg-blue-500 text-white text-[9px] font-black w-[18px] h-[18px] rounded-full flex items-center justify-center border-2 border-[#0d1526]">
                  {cartCount > 9 ? "9+" : cartCount}
                </span>
              )}
            </Link>

            {/* Profile */}
            <Link
              to="/b2b/account"
              aria-label="Account"
              className={`flex items-center justify-center w-10 h-10 rounded-xl border transition-all ${
                isActive("/b2b/account")
                  ? "bg-blue-600 border-blue-500 text-white"
                  : "bg-white/5 border-white/10 text-slate-300 hover:text-white hover:bg-white/10"
              }`}
            >
              <User size={17} />
            </Link>

            {/* Logout — desktop */}
            <button
              onClick={handleLogout}
              aria-label="Logout"
              className="hidden sm:flex items-center justify-center w-10 h-10 bg-white/5 border border-white/10 rounded-xl text-rose-400 hover:bg-rose-500/10 hover:border-rose-500/30 transition-all"
            >
              <LogOut size={17} />
            </button>

            {/* Hamburger — mobile */}
            <button
              onClick={() => setMobileOpen(!mobileOpen)}
              aria-label="Menu"
              className="flex md:hidden items-center justify-center w-10 h-10 bg-white/5 border border-white/10 rounded-xl text-slate-300 hover:text-white hover:bg-white/10 transition-all"
            >
              {mobileOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
          </div>
        </div>
      </header>

      {/* ── Mobile Drawer ── */}
      {mobileOpen && (
        <div
          className="md:hidden fixed inset-0 top-[80px] z-40"
          onClick={() => setMobileOpen(false)}
        >
          {/* Backdrop */}
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />

          {/* Sheet */}
          <div
            className="relative bg-[#0d1526] border-b border-white/10 px-4 pt-5 pb-6 flex flex-col gap-2 shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Profile chip */}
            {profile && (
              <div className="flex items-center gap-3 p-3 bg-white/5 border border-white/10 rounded-xl mb-3">
                <div className="w-9 h-9 rounded-xl bg-blue-600 flex items-center justify-center text-white font-black text-sm shrink-0">
                  {(profile.institutionName || "?")[0].toUpperCase()}
                </div>
                <div className="min-w-0">
                  <p className="text-[13px] font-black text-white truncate">{profile.institutionName}</p>
                  <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mt-0.5">
                    {profile.isVerified ? "Verified Account" : "Pending Verification"}
                  </p>
                </div>
                {profile.isVerified
                  ? <CheckCircle2 size={16} className="text-emerald-400 ml-auto shrink-0" />
                  : <span className="w-2.5 h-2.5 rounded-full bg-amber-400 animate-pulse ml-auto shrink-0" />
                }
              </div>
            )}

            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setMobileOpen(false)}
                className={`flex items-center h-12 px-4 rounded-xl text-[14px] font-bold transition-colors ${
                  isActive(link.path)
                    ? "bg-blue-500/10 text-blue-400 border border-blue-500/20"
                    : "text-slate-300 hover:bg-white/5 hover:text-white"
                }`}
              >
                {link.label}
              </Link>
            ))}

            <div className="mt-2 pt-3 border-t border-white/10">
              <button
                onClick={handleLogout}
                className="w-full flex items-center justify-center gap-2 h-12 rounded-xl bg-rose-500/10 border border-rose-500/20 text-rose-400 font-bold text-sm"
              >
                <LogOut size={16} /> Sign Out
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default B2bHeader;
